import { useMemo, useState } from 'react';
import { useToast } from '../components/common/ToastProvider';
import { submitSupportFeedback } from '../api/support.api';

function Support() {
  const { pushToast } = useToast();
  const [form, setForm] = useState({
    type: 'ISSUE',
    email: '',
    subject: '',
    message: ''
  });
  const [loading, setLoading] = useState(false);

  const canSubmit = useMemo(
    () => form.email.trim() && form.subject.trim() && form.message.trim(),
    [form.email, form.message, form.subject]
  );

  const submit = async (e) => {
    e.preventDefault();
    if (!canSubmit) return;

    try {
      setLoading(true);
      await submitSupportFeedback(form);
      pushToast('Support request submitted successfully.', 'success');
      setForm({ type: 'ISSUE', email: '', subject: '', message: '' });
    } catch (error) {
      const message = error?.response?.data?.error || error?.response?.data?.message || 'Unable to submit right now. Please try again.';
      pushToast(message, 'danger');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className='container py-4'>
      <div className='card card-soft p-4 mb-3'>
        <h2>About RescueLink</h2>
        <h5 className='mt-3'>Overview</h5>
        <p>
          RescueLink is a smart emergency coordination platform designed to provide quick access to
          critical services during urgent situations. The platform enables users to trigger SOS alerts,
          share their location, find nearby hospitals, and connect with blood donors through a single,
          easy-to-use interface.
        </p>
        <p>
          By bringing essential emergency resources together, RescueLink helps reduce response time and
          improves communication when every second matters.
        </p>

        <h5 className='mt-3'>Our Mission</h5>
        <p>
          To leverage technology to provide a reliable and accessible emergency support system that
          empowers individuals to seek and receive help quickly during critical situations.
        </p>

        <h5 className='mt-3'>What RescueLink Offers</h5>
        <ul>
          <li><strong>Instant SOS Alerts</strong>: Users can trigger emergency alerts with location sharing to notify responders immediately.</li>
          <li><strong>Hospital Locator</strong>: Find nearby hospitals and access their contact details quickly.</li>
          <li><strong>Blood Donor Network</strong>: Search and connect with verified donors based on blood group and availability.</li>
          <li><strong>Real-Time Updates</strong>: Track the status of emergency requests and receive notifications.</li>
          <li><strong>Admin Monitoring</strong>: Ensures data reliability through verification and system monitoring.</li>
        </ul>

        <h5 className='mt-3'>Why RescueLink Matters</h5>
        <p>
          In emergency situations, delays often occur because people struggle to find reliable help
          quickly. RescueLink addresses this challenge by providing a centralized digital platform that
          simplifies access to emergency services and enhances coordination during crises.
        </p>

        <h5 className='mt-3'>Who Can Use RescueLink</h5>
        <ul>
          <li>Individuals seeking emergency assistance</li>
          <li>Hospitals and healthcare providers</li>
          <li>Blood donors and recipients</li>
          <li>Emergency coordinators</li>
        </ul>

        <h5 className='mt-3'>Our Commitment</h5>
        <p>
          RescueLink prioritizes usability, reliability, and user safety. The platform is designed to be
          simple, fast, and accessible so that help can be requested with minimal effort during stressful
          situations.
        </p>
        <p className='mb-0'><strong>Tagline:</strong> Connecting people to life-saving help when it matters most.</p>
      </div>

      <div className='card card-soft p-4'>
        <h2>Support / Contact</h2>
        <p className='text-muted'>Submit issues and feedback to improve RescueLink.</p>
        <form className='row g-3' onSubmit={submit}>
          <div className='col-md-4'>
            <label className='form-label'>Type</label>
            <select
              className='form-select'
              value={form.type}
              onChange={(e) => setForm((prev) => ({ ...prev, type: e.target.value }))}
            >
              <option value='ISSUE'>Issue</option>
              <option value='FEEDBACK'>Feedback</option>
            </select>
          </div>
          <div className='col-md-8'>
            <label className='form-label'>Email</label>
            <input
              type='email'
              className='form-control'
              value={form.email}
              onChange={(e) => setForm((prev) => ({ ...prev, email: e.target.value }))}
              placeholder='name@example.com'
            />
          </div>
          <div className='col-12'>
            <label className='form-label'>Subject</label>
            <input
              className='form-control'
              value={form.subject}
              onChange={(e) => setForm((prev) => ({ ...prev, subject: e.target.value }))}
              placeholder='Short summary'
            />
          </div>
          <div className='col-12'>
            <label className='form-label'>Message</label>
            <textarea
              className='form-control'
              rows='5'
              value={form.message}
              onChange={(e) => setForm((prev) => ({ ...prev, message: e.target.value }))}
              placeholder='Describe your issue or suggestion...'
            />
          </div>
          <div className='col-12 d-grid d-md-flex justify-content-md-end'>
            <button className='btn btn-danger' disabled={!canSubmit || loading}>
              {loading ? 'Submitting...' : 'Send'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

export default Support;
